const fs = require('fs');
const path = require('path');

const FILE = path.join(__dirname, 'index.html');
if (!fs.existsSync(FILE)) { console.error('Not found: index.html'); process.exit(1); }

let html = fs.readFileSync(FILE, 'utf8');
let count = 0;

function imgTag(b64, ext, alt) {
  return `<img src="data:image/${ext};base64,${b64}" alt="${alt}" style="width:100%;height:100%;object-fit:cover;border-radius:8px;display:block"/>`;
}

function videoTag(b64) {
  return `<video autoplay muted loop playsinline style="width:100%;height:100%;object-fit:cover;border-radius:8px;display:block" src="data:video/mp4;base64,${b64}"></video>`;
}


// 3D Asset Gen
(function() {
  var old = '<div class="tool-card">\n    <div class="tc-icon">◈</div>\n    <div class="tc-name">3D Asset Gen</div>\n    <div class="tc-desc">Text to rigged 3D mesh in seconds</div>\n  </div>';
  var neu = '<div class="tool-card" style="padding:0;overflow:hidden;position:relative;min-height:140px">\n    <img src="data:image/jpg;base64," alt="3D Asset Gen" style="width:100%;height:100%;object-fit:cover;border-radius:8px;display:block"/>\n    <div style="position:absolute;bottom:0;left:0;right:0;padding:10px 12px;background:linear-gradient(transparent,rgba(0,0,0,.9))">\n      <div class="tc-name" style="font-size:13px">3D Asset Gen</div>\n      <div class="tc-desc" style="font-size:11px">Text to rigged 3D mesh in seconds</div>\n    </div>\n  </div>';
  if (html.includes(old)) {
    html = html.replace(old, neu);
    count++;
    console.log('✅  3D Asset Gen wired');
  } else {
    console.log('⚠️   3D Asset Gen - pattern not found, may need manual check');
  }
})();

